  "inlineSchema": "// ================================================================\n// Prisma Schema — SchoolSpace Backend\n// Provider: PostgreSQL (Neon)\n// ================================================================\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// -----------------------------------------------------------------\n// Models\n// -----------------------------------------------------------------\n\nmodel User {\n  id        String   @id @default(uuid())\n  email     String   @unique\n  password  String\n  role      String // \"ADMIN\" | \"TEACHER\" | \"STUDENT\"\n  name      String\n  phone     String?\n  avatar    String?\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  studentProfile Student?\n  teacherProfile Teacher?\n\n  messagesSent     Message[] @relation(\"Sender\")\n  messagesReceived Message[] @relation(\"Receiver\")\n\n  @@index([role])\n  @@index([createdAt])\n}\n\nmodel Class {\n  id       String    @id @default(uuid())\n  name     String\n  sections Section[]\n}\n\nmodel Section {\n  id      String @id @default(uuid())\n  name    String\n  classId String\n  class   Class  @relation(fields: [classId], references: [id])\n\n  students Student[]\n  subjects Subject[]\n\n  @@index([classId])\n}\n\nmodel Subject {\n  id        String  @id @default(uuid())\n  name      String\n  code      String\n  sectionId String\n  section   Section @relation(fields: [sectionId], references: [id])\n\n  teacherId String?\n  teacher   Teacher? @relation(fields: [teacherId], references: [id], onDelete: SetNull)\n\n  marks       Mark[]\n  assignments Assignment[]\n  attendances Attendance[]\n\n  @@index([sectionId])\n  @@index([teacherId])\n}\n\nmodel GalleryItem {\n  id          String   @id @default(uuid())\n  title       String\n  imageUrl    String\n  description String?\n  createdAt   DateTime @default(now())\n}\n\nmodel StaffProfile {\n  id        String   @id @default(uuid())\n  name      String\n  role      String\n  bio       String?\n  imageUrl  String?\n  isHead    Boolean  @default(false)\n  sortOrder Int      @default(0)\n  createdAt DateTime @default(now())\n}\n\nmodel SiteStat {\n  id        String   @id @default(uuid())\n  key       String   @unique\n  label     String\n  value     String\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nmodel Event {\n  id          String   @id @default(uuid())\n  title       String\n  date        DateTime\n  type        String // \"ACADEMIC\" | \"HOLIDAY\" | \"CULTURAL\" etc.\n  description String?\n  imageUrl    String?\n  createdAt   DateTime @default(now())\n\n  @@index([date])\n  @@index([type])\n}\n\nmodel RoutineEntry {\n  id          String   @id @default(uuid())\n  className   String // e.g. \"Class 10\"\n  section     String // e.g. \"A\"\n  dayOfWeek   String // \"SAT\", \"SUN\", ...\n  startTime   String // \"09:00\"\n  endTime     String // \"09:45\"\n  subject     String\n  teacherName String\n  room        String?\n  createdAt   DateTime @default(now())\n\n  @@index([className, section])\n  @@index([dayOfWeek])\n}\n\nmodel Student {\n  id     String @id @default(cuid())\n  userId String @unique\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  rollNo    Int\n  sectionId String\n  section   Section @relation(fields: [sectionId], references: [id])\n\n  marks       Mark[]\n  attendances Attendance[]\n  submissions Submission[]\n\n  @@index([sectionId])\n  @@index([rollNo])\n}\n\nmodel Teacher {\n  id     String @id @default(cuid())\n  userId String @unique\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  specialization String?\n  photoUrl       String?\n  bio            String?\n  qualifications String?\n  experience     String?\n  isFeatured     Boolean @default(false)\n\n  subjects Subject[]\n\n  @@index([userId])\n  @@index([isFeatured])\n}\n\nmodel Attendance {\n  id     String   @id @default(uuid())\n  date   DateTime\n  status String // \"PRESENT\" | \"ABSENT\" | \"LATE\"\n\n  studentId String\n  student   Student @relation(fields: [studentId], references: [id], onDelete: Cascade)\n\n  subjectId String?\n  subject   Subject? @relation(fields: [subjectId], references: [id])\n\n  createdAt DateTime @default(now())\n\n  @@unique([studentId, subjectId, date])\n  @@index([studentId])\n  @@index([date])\n  @@index([subjectId])\n}\n\nmodel Mark {\n  id         String @id @default(uuid())\n  examType   String // \"CLASS_TEST\" | \"MID\" | \"FINAL\"\n  score      Float\n  totalScore Float\n\n  studentId String\n  student   Student @relation(fields: [studentId], references: [id], onDelete: Cascade)\n\n  subjectId String\n  subject   Subject @relation(fields: [subjectId], references: [id], onDelete: Cascade)\n\n  createdAt DateTime @default(now())\n\n  @@index([studentId])\n  @@index([subjectId])\n}\n\nmodel Assignment {\n  id          String   @id @default(uuid())\n  title       String\n  description String?\n  dueDate     DateTime\n  fileUrl     String?\n\n  subjectId String\n  subject   Subject @relation(fields: [subjectId], references: [id], onDelete: Cascade)\n\n  submissions Submission[]\n\n  @@index([subjectId])\n  @@index([dueDate])\n}\n\nmodel Submission {\n  id          String   @id @default(uuid())\n  fileUrl     String?\n  submittedAt DateTime @default(now())\n\n  assignmentId String\n  assignment   Assignment @relation(fields: [assignmentId], references: [id], onDelete: Cascade)\n\n  studentId String\n  student   Student @relation(fields: [studentId], references: [id], onDelete: Cascade)\n\n  @@unique([assignmentId, studentId])\n  @@index([assignmentId])\n  @@index([studentId])\n}\n\nmodel Notice {\n  id             String   @id @default(uuid())\n  title          String\n  content        String\n  type           String // \"GENERAL\" | \"ACADEMIC\" | \"EMERGENCY\"\n  featuredOnHome Boolean  @default(false) // larger priority on homepage board\n  floatOnHome    Boolean  @default(false) // floating notice chips on homepage (admin only)\n  createdAt      DateTime @default(now())\n\n  @@index([type])\n  @@index([createdAt])\n  @@index([featuredOnHome])\n}\n\n// Single-row homepage snippets (Quran, Hadith, motivation) — admin-editable\nmodel HomeDailyContent {\n  id           String   @id @default(\"default\")\n  quranText    String   @default(\"\")\n  quranRef     String   @default(\"\")\n  hadithText   String   @default(\"\")\n  hadithRef    String   @default(\"\")\n  motivational String   @default(\"\")\n  updatedAt    DateTime @updatedAt\n}\n\nmodel Message {\n  id        String   @id @default(uuid())\n  content   String\n  createdAt DateTime @default(now())\n  isRead    Boolean  @default(false)\n\n  senderId String\n  sender   User   @relation(\"Sender\", fields: [senderId], references: [id])\n\n  receiverId String\n  receiver   User   @relation(\"Receiver\", fields: [receiverId], references: [id])\n\n  @@index([senderId])\n  @@index([receiverId])\n  @@index([createdAt])\n}\n\nmodel ContactRequest {\n  id        String   @id @default(uuid())\n  name      String\n  email     String\n  message   String\n  createdAt DateTime @default(now())\n  isRead    Boolean  @default(false)\n\n  @@index([createdAt])\n}\n",
